/**
 * @param {string[]} words
 * @return {number[]}
 */
function solve(words) {
    const n = words.length;
    const answer = new Array(n).fill(0);

    // Build a trie for all words
    const trie = new Trie();
    for (const word of words) {
        trie.insert(word);
    }

    // For each index i, remove the word at i and find the max prefix length
    for (let i = 0; i < n; i++) {
        // Remove the word at index i
        const word = words[i];
        // Rebuild the trie without the word at index i
        trie.clear();
        for (let j = 0; j < n; j++) {
            if (j !== i) {
                trie.insert(words[j]);
            }
        }

        // Find the max prefix length between adjacent words
        let maxPrefix = 0;
        for (let j = 0; j < n - 1; j++) {
            if (j !== i) {
                const prefix = trie.getLongestCommonPrefix(words[j], words[j + 1]);
                maxPrefix = Math.max(maxPrefix, prefix);
            }
        }
        answer[i] = maxPrefix;
    }

    return answer;
}

class TrieNode {
    constructor() {
        this.children = {};
    }
}

class Trie {
    constructor() {
        this.root = new TrieNode();
    }

    insert(word) {
        let node = this.root;
        for (const char of word) {
            if (!node.children[char]) {
                node.children[char] = new TrieNode();
            }
            node = node.children[char];
        }
    }

    clear() {
        this.root = new TrieNode();
    }

    getLongestCommonPrefix(word1, word2) {
        let i = 0;
        while (i < word1.length && i < word2.length && word1[i] === word2[i]) {
            i++;
        }
        return i;
    }
}

